content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
.chip-toolbar { padding: 10px 16px; background: #fff; border-radius: 12px; border: 1px solid #e5e7eb; margin-bottom: 12px; font-size: 12px; color: #6b7280; display: flex; align-items: center; flex-wrap: wrap; gap: 4px; }
.chip { display: inline-block; padding: 4px 12px; margin: 0 2px; border-radius: 14px; background: #f3f4f6; color: #4b5563; cursor: pointer; transition: all 0.15s; font-size: 12px; user-select: none; }
.chip:hover { background: #e5e7eb; }
.chip.active { background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); color: #fff; font-weight: 600; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
/**
 * 04-门店每日指挥台 (chip toolbar 版)
 * 每个 dataView 含 门店类型 row, JS 侧根据 activeType filter columnar data
 */
(function autoBootstrap(){
  setTimeout(function(){
    try{
      var root=document.getElementById('dash-root');
      if(!root||root.innerText.indexOf('加载中')<0)return;
      var cdId='t43252011a583ee4d3e71fc1';  // customChart cdId
      fetch(window.parent.location.origin+'/api/card/'+cdId+'/data',{
        method:'POST',headers:{'Content-Type':'application/json'},body:'{}',credentials:'include',
      }).then(function(r){return r.json();}).then(function(j){
        if(!j.viewData)return;
        var data=j.viewData.map(function(v){return v.chartMain.columns;});
        window.__rawData=data;
        if(typeof renderChart==='function')renderChart(data,function(){},{});
      });
    }catch(e){console.error('autoBootstrap fail:',e);}
  },4000);
})();

var ALL_TYPES=['商场店','社区店','写字楼店','交通店','学校店','夜市店','外卖卫星店','旗舰店','快取店'];
var activeType='ALL';

function changeType(t){activeType=t;if(window.__rawData)renderChart(window.__rawData);}

function renderToolbar(){
  var chips='<span class="chip '+(activeType==='ALL'?'active':'')+'" onclick="changeType(\'ALL\')">全部 (1200)</span>';
  ALL_TYPES.forEach(function(t){
    chips+='<span class="chip '+(activeType===t?'active':'')+'" onclick="changeType(\''+t+'\')">'+t+'</span>';
  });
  return '<div class="chip-toolbar">📍 门店类型: '+chips+'</div>';
}

// 按 activeType filter columnar data
function filterDataByType(data,t){
  if(t==='ALL')return data;
  return data.map(function(view){
    if(!view||!view.length)return view;
    var typeCol=null;
    for(var i=0;i<view.length;i++){if(view[i].name==='门店类型'){typeCol=view[i];break;}}
    if(!typeCol)return view;
    var keepIdx=[];
    for(var i=0;i<typeCol.data.length;i++){if(typeCol.data[i]===t)keepIdx.push(i);}
    return view.map(function(col){
      return {name:col.name,type:col.type,data:keepIdx.map(function(i){return col.data[i];})};
    });
  });
}

function fmtNum(v){if(v==null||isNaN(v))return"—";v=Number(v);if(Math.abs(v)>=1e8)return(v/1e8).toFixed(2)+" 亿";if(Math.abs(v)>=1e4)return(v/1e4).toFixed(1)+" 万";return Math.round(v).toLocaleString();}
function fmtPct(v){if(v==null||isNaN(v))return"—";return(Number(v)*100).toFixed(1)+"%";}
function getCol(view,name){if(!view)return null;for(var i=0;i<view.length;i++){if(view[i]&&view[i].name===name)return view[i];}return null;}
function sumArr(a){var s=0;if(!a)return 0;for(var i=0;i<a.length;i++){var v=Number(a[i]);if(!isNaN(v))s+=v;}return s;}
function esc(v){if(v==null)return"";return String(v).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}

function renderChart(data){
  var root=document.getElementById('dash-root');
  if(!data||!data[0]){root.innerHTML='<div class="dash-loading">No data</div>';return;}
  window.__rawData=data;
  data=filterDataByType(data,activeType);  // 关键: filter data 后再渲染
  var toolbarHTML=renderToolbar();

  // dataView 0: 异常分布
  var v0=data[0];
  var aType=(getCol(v0,"今日异常")||{}).data||[];
  var aStoreDays=(getCol(v0,"门店ID")||{}).data||[];
  var aSales=(getCol(v0,"销售额")||{}).data||[];

  // KPI
  var totalSales=sumArr(aSales);
  var totalStoreDays=sumArr(aStoreDays);
  var normalIdx=aType.indexOf("正常");
  var normalDays=normalIdx>=0?Number(aStoreDays[normalIdx])||0:0;
  var abnormalDays=totalStoreDays-normalDays;
  var abnormalRate=totalStoreDays?abnormalDays/totalStoreDays:0;

  // dataView 1: 城市层级
  var v1=data[1];
  var tierCol=(getCol(v1,"城市层级")||{}).data||[];
  var styCol=(getCol(v1,"店型")||{}).data||[];
  var tSales=(getCol(v1,"销售额")||{}).data||[];
  var tOrder=(getCol(v1,"订单数")||{}).data||[];
  var tStores=(getCol(v1,"门店ID")||{}).data||[];

  // dataView 2: Top 门店 (按销售排序后切前 15)
  var v2=data[2];
  var sName=(getCol(v2,"门店名称")||{}).data||[];
  var sCity=(getCol(v2,"城市")||{}).data||[];
  var sStyle=(getCol(v2,"店型")||{}).data||[];
  var sSales2=(getCol(v2,"销售额")||{}).data||[];
  var sOrders=(getCol(v2,"订单数")||{}).data||[];
  var sRating=(getCol(v2,"当日评分")||{}).data||[];
  var sNeg=(getCol(v2,"未回复负评数")||{}).data||[];
  var storeRows=[];
  for(var i=0;i<sName.length;i++){
    storeRows.push({name:sName[i],city:sCity[i],style:sStyle[i],sales:Number(sSales2[i])||0,orders:Number(sOrders[i])||0,rating:Number(sRating[i])||0,neg:Number(sNeg[i])||0});
  }
  storeRows.sort(function(a,b){return b.sales-a.sales;});
  var top10=storeRows.slice(0,10);

  root.innerHTML=(
    toolbarHTML+
    '<div class="dash-header">'+
      '<div class="dash-title">🏪 门店每日指挥台'+(activeType!=='ALL'?' · <span style="color:#d97706;font-size:14px;">已筛选: '+activeType+'</span>':'')+'</div>'+
      '<div class="dash-sub">店长视角 · 营收 + 异常 + Top 标杆 · '+(activeType==='ALL'?'1200':totalStoreDays)+' '+(activeType==='ALL'?'家门店':'店日数')+'</div>'+
    '</div>'+
    '<div class="kpi-row">'+
      '<div class="kpi-card"><div class="kpi-label">总营收 (累计)</div><div class="kpi-value">'+fmtNum(totalSales)+'</div><div class="kpi-trend">▲ 多店协同</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">总店日数</div><div class="kpi-value">'+fmtNum(totalStoreDays)+'</div><div class="kpi-trend">'+fmtNum(top10.length)+'+ 门店</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">异常店日占比</div><div class="kpi-value '+(abnormalRate>0.20?'down':'')+'">'+fmtPct(abnormalRate)+'</div><div class="kpi-trend">'+fmtNum(abnormalDays)+' 店日</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">门店日均销售</div><div class="kpi-value">'+fmtNum(totalStoreDays?totalSales/totalStoreDays:0)+'</div><div class="kpi-trend neutral">元 / 店 / 天</div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">今日异常分布 <span class="tag">告警 4 类</span></div><div id="c-alert" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">城市层级 × 店型·销售额 <span class="tag">堆叠对比</span></div><div id="c-tier" class="chart-body"></div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">Top 10 门店·销售排行 <span class="tag">标杆</span></div><div id="c-top" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">Top 10 门店明细 <span class="tag">含评分</span></div><div id="c-store-tbl" style="height:260px;overflow:auto;">'+
        '<table class="dash-tbl"><thead><tr><th>排名</th><th>门店</th><th>城市</th><th>店型</th><th>销售</th><th>订单</th><th>评分</th></tr></thead><tbody>'+
        top10.map(function(s,i){
          var ratingTag=s.rating<4?'<span class="tag-risk 高风险">⚠'+s.rating.toFixed(1)+'</span>':'<span class="tag-risk 正常">'+s.rating.toFixed(1)+'</span>';
          return '<tr><td><b>'+(i+1)+'</b></td><td>'+esc(s.name)+'</td><td>'+esc(s.city)+'</td><td>'+esc(s.style)+'</td><td><b>'+fmtNum(s.sales)+'</b></td><td>'+fmtNum(s.orders)+'</td><td>'+ratingTag+'</td></tr>';
        }).join('')+
        '</tbody></table></div></div>'+
    '</div>'
  );

  function ch(id){return echarts.init(document.getElementById(id));}
  function baseTooltip(){return {backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},extraCssText:'box-shadow:0 4px 12px rgba(15,23,42,0.08);border-radius:6px;'};}

  // 1. 异常分布 - 饼图
  var alertColors={"正常":"#059669","客流异常":"#fbbf24","负评待处理":"#dc2626","折扣过高":"#f59e0b"};
  var alertData=[];
  for(var i=0;i<aType.length;i++){
    var t=aType[i];
    alertData.push({name:t,value:Number(aStoreDays[i])||0,itemStyle:{color:alertColors[t]||'#94a3b8'}});
  }
  ch('c-alert').setOption({
    backgroundColor:'transparent',
    tooltip:{trigger:'item',...baseTooltip(),formatter:function(p){return p.name+'<br/>'+fmtNum(p.value)+' 店日 ('+p.percent+'%)';}},
    legend:{orient:'vertical',right:10,top:'middle',textStyle:{color:'#6b7280',fontSize:11}},
    series:[{type:'pie',radius:['45%','70%'],center:['35%','50%'],avoidLabelOverlap:true,itemStyle:{borderColor:'#fff',borderWidth:2},label:{show:true,formatter:'{b}\n{d}%',color:'#374151',fontSize:10},data:alertData}]
  });

  // 2. 城市层级 × 店型 堆叠柱
  var tierMap={};
  var tiers=["一线","新一线","二线","三线"];
  var styles=["旗舰店","标准店","快取店","外卖店","校园店"];
  tiers.forEach(function(t){tierMap[t]={};});
  for(var i=0;i<tierCol.length;i++){
    if(!tierMap[tierCol[i]])tierMap[tierCol[i]]={};
    tierMap[tierCol[i]][styCol[i]]=(tierMap[tierCol[i]][styCol[i]]||0)+(Number(tSales[i])||0);
  }
  var stColors={"旗舰店":"#dc2626","标准店":"#2563eb","快取店":"#0891b2","外卖店":"#f59e0b","校园店":"#a855f7"};
  var ser=styles.map(function(s){return {name:s,type:'bar',stack:'all',itemStyle:{color:stColors[s]},data:tiers.map(function(t){return tierMap[t][s]||0;})};});
  ch('c-tier').setOption({
    backgroundColor:'transparent',
    legend:{data:styles,textStyle:{color:'#6b7280'},top:0,right:10},
    tooltip:{trigger:'axis',axisPointer:{type:'shadow'},...baseTooltip(),formatter:function(p){var s='<b>'+p[0].name+'</b><br/>';p.forEach(function(x){if(x.value)s+=x.marker+x.seriesName+': '+fmtNum(x.value)+'<br/>';});return s;}},
    grid:{left:60,right:20,top:35,bottom:30},
    xAxis:{type:'category',data:tiers,axisLabel:{color:'#374151',fontSize:11},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    yAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    series:ser
  });

  // 3. Top 10 销售横向条
  ch('c-top').setOption({
    backgroundColor:'transparent',
    tooltip:{trigger:'item',...baseTooltip(),formatter:function(p){return p.name+'<br/>销售: '+fmtNum(p.value);}},
    grid:{left:150,right:50,top:5,bottom:25},
    xAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    yAxis:{type:'category',data:top10.map(function(s){return s.name;}).reverse(),axisLabel:{color:'#374151',fontSize:10},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    series:[{type:'bar',data:top10.map(function(s){return s.sales;}).reverse(),itemStyle:{color:new echarts.graphic.LinearGradient(0,0,1,0,[{offset:0,color:'#2563eb'},{offset:1,color:'#0891b2'}]),borderRadius:[0,4,4,0]},label:{show:true,position:'right',color:'#374151',formatter:function(p){return fmtNum(p.value);}}}]
  });
}

new GDPlugin().init(renderChart);
